Mock responses for a GET /api/orders/{id} endpoint, generated to match the contract and wired into MSW:
```javascript
import { http, HttpResponse } from 'msw'

export const handlers = [
  // 200 success
  http.get('/api/orders/:id', ({ params }) => {
    if (params.id === '404') {
      return HttpResponse.json(
        { data: null, error: { code: 'NOT_FOUND', message: 'Order not found' } },
        { status: 404 }
      )
    }
    if (params.id === '500') {
      return HttpResponse.json(
        { data: null, error: { code: 'INTERNAL', message: 'Server error' } },
        { status: 500 }
      )
    }
    return HttpResponse.json(
      {
        data: { id: params.id, status: 'shipped', total: 129.99, currency: 'USD' },
        error: null
      },
      { status: 200, headers: { 'Content-Type': 'application/json' } }
    )
  }),
]
```

A minimal, safe agent loop (pseudocode) for triaging a bug report. Note the read-only tool, the iteration cap, and the human gate:
```python
MAX_STEPS = 5
tools = {
    "search_issues": search_issues_readonly,  # read-only API
}

def triage_agent(report):
    context = [f"Goal: classify and find duplicates for this bug report:\n{report}"]
    for step in range(MAX_STEPS):
        decision = llm_decide(context, tools.keys())  # returns action + args
        if decision.action == "final":
            break
        result = tools[decision.action](**decision.args)
        context.append(f"Tool {decision.action} -> {result}")

    proposal = {
        "severity": decision.severity,
        "component": decision.component,
        "possible_duplicate": decision.duplicate_id,
    }
    # Human-in-the-loop: agent suggests, human approves. It never closes/merges itself.
    return require_human_approval(proposal)
```
